/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on parent update restrict */
/* %ErwinRelationInfo */
IF
  /* %%ParentPK(" OR",UPDATE) */
  %ParentPK(" OR",UPDATE)
BEGIN
  IF EXISTS (
    SELECT * FROM deleted,%Child
    WHERE
      /*  %%JoinFKPK(%Child,deleted," = "," AND") */
      %JoinFKPK(%Child,deleted," = "," AND")
  )
  BEGIN
    SELECT @errno  = 30005,
           @errmsg = 'Cannot update %Parent because %Child exists.'
    GOTO error
  END
END

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on parent update set null */
/* %ErwinRelationInfo */
IF
  /* %%ParentPK(" OR",UPDATE) */
  %ParentPK(" OR",UPDATE)
BEGIN
  UPDATE %Child
    SET
      /* %%SetFK(%Child,NULL) */
      %SetFK(%Child,NULL)
    FROM %Child,deleted
    WHERE
      /* %%JoinFKPK(%Child,deleted," = "," AND") */
      %JoinFKPK(%Child,deleted," = "," AND")
END

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on parent delete restrict */
/* %ErwinRelationInfo */
IF EXISTS (
  SELECT * FROM deleted,%Child
  WHERE
    /*  %%JoinFKPK(%Child,deleted," = "," AND") */
    %JoinFKPK(%Child,deleted," = "," AND")
)
BEGIN
  SELECT @errno  = 30001,
         @errmsg = 'Cannot delete %Parent because %Child exists.'
  GOTO error
END

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on parent delete cascade */
/* %ErwinRelationInfo */
DELETE %Child
  FROM %Child,deleted
  WHERE
    /*  %%JoinFKPK(%Child,deleted," = "," AND") */
    %JoinFKPK(%Child,deleted," = "," AND")

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on parent delete set null */
/* %ErwinRelationInfo */
UPDATE %Child
  SET
    /* %%SetFK(%Child,NULL) */
    %SetFK(%Child,NULL)
  FROM %Child,deleted
  WHERE
    /* %%JoinFKPK(%Child,deleted," = "," AND") */
    %JoinFKPK(%Child,deleted," = "," AND")

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on child insert restrict */
/* %ErwinRelationInfo */
IF
  /* %%ChildFK(" OR",UPDATE) */
  %ChildFK(" OR",UPDATE)
BEGIN
  SELECT @nullcnt = 0
  SELECT @validcnt = count(*)
    FROM inserted,%Parent
      WHERE
        /* %%JoinFKPK(inserted,%Parent) */
        %JoinFKPK(inserted,%Parent)
  /* %%NotnullFK(inserted," IS NULL","select @nullcnt = count(*) from inserted where"," and") */
  %NotnullFK(inserted," IS NULL","select @nullcnt = count(*) from inserted where"," and")
  IF @validcnt + @nullcnt != @numrows
  BEGIN
    SELECT @errno  = 30002,
           @errmsg = 'Cannot insert %Child because %Parent does not exist.'
    GOTO error
  END
END

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on child insert cascade */
/* %ErwinRelationInfo */
IF
  /* %%ChildFK(" OR",UPDATE) */
  %ChildFK(" OR",UPDATE)
BEGIN
  INSERT %Parent (%ParentPK(",",))
    SELECT %ChildFK(",",)
    FROM   inserted
    WHERE
      /* %%NotnullFK(inserted," IS NOT NULL AND") */
      %NotnullFK(inserted," IS NOT NULL AND")
      NOT EXISTS (
        SELECT * FROM %Parent
        WHERE
          /* %%JoinFKPK(inserted,%Parent," = "," AND") */
          %JoinFKPK(inserted,%Parent," = "," AND")
      )
END

/* erwin Builtin Trigger */
/* %Parent %VerbPhrase %Child on child insert set null */
/* %ErwinRelationInfo */
IF
  /* %%ChildFK(" OR",UPDATE) */
  %ChildFK(" OR",UPDATE)
BEGIN
  UPDATE %Child
    SET
      /* %%SetFK(%Child,NULL) */
      %SetFK(%Child,NULL)
    FROM %Child,inserted
    WHERE
      /* %%JoinPKPK(%Child,inserted," = "," AND") */
     %if(%!=(%Len(%JoinPKPK(%Child,inserted," = "," AND")),0)) 
     { 
      %JoinPKPK(%Child,inserted," = "," AND") AND
     } 
      NOT EXISTS (
        SELECT * FROM %Parent
        WHERE
          /* %%JoinFKPK(inserted,%Parent," = "," AND") */
          %JoinFKPK(inserted,%Parent," = "," AND")
      )
END

