CREATE %TLX(@if(IsPropertyTrue("Use_Alter_Syntax")) {"OR ALTER "})TRIGGER %If(%TriggerName) {%ProcedureOwner(.)%TriggerName} %Else {%ProcedureOwner(.)t%1Action_%---TableName} ON %TableOwner(.)%TableName FOR %Action AS
/* erwin Builtin Trigger */
/* %Action trigger on %TableName */
BEGIN
  DECLARE  @numrows int,
           @nullcnt int,
           @validcnt int,
           %PKDecl(,@ins)%decl(bComma,0)%ForEachAtt() {%if(%AttIsPk) {%=(bComma,1)} }%if (%==(%:bComma,1)) {,}
           @errno   int,
           @severity int,
           @state    int,
           @errmsg  varchar(255)

  SELECT @numrows = @@rowcount

  /* erwin Builtin Trigger */
  RETURN
error:
   RAISERROR (@errmsg, -- Message text.
              @severity, -- Severity (0~25).
              @state) -- State (0~255).
    rollback transaction
END
%DBMSDelim

