CREATE %TLX(@if(IsPropertyTrue("Use_Alter_Syntax")) {"OR ALTER "})TRIGGER %ProcedureOwner(.)%TriggerName ON %TableOwner(.)%TableName
   %SQLServerWithOptions %Fire %Actions(",") 
 %ProcedureProps 
  AS
/* erwin Builtin Trigger */
/* %Actions(",") trigger on %TableName */
/* default body for %TriggerName */
BEGIN
  DECLARE  @numrows int,
           @nullcnt int,
           @validcnt int,
           %PKDecl(,@ins)%decl(bComma,0)%ForEachAtt() {%if(%AttIsPk) {%=(bComma,1)} }%if (%==(%:bComma,1)) {,}
           @errno   int,
           @severity int,
           @state    int,
           @errmsg  varchar(255)

  SELECT @numrows = @@rowcount
%ForEachChildRel() {
  %RelTemplate
}
%ForEachParentRel() {
  %RelTemplate
}
  RETURN
error:
   RAISERROR (@errmsg, -- Message text.
              @severity, -- Severity (0~25).
              @state) -- State (0~255).
    rollback transaction
END
%DBMSDelim

